import 'package:flutter/material.dart';\nimport 'package:flutter_riverpod/flutter_riverpod.dart';\nimport 'dart:async';\nimport 'package:timezone/timezone.dart' as tz;\nimport 'package:timezone/data/latest.dart' as tzdata;\n\n// Provider for current time (updates every second)\nfinal currentTimeProvider = StreamProvider<DateTime>((ref) {\n  return Stream.periodic(\n    const Duration(seconds: 1),\n    (_) => DateTime.now(),\n  );\n});\n\n// Provider for selected time zones\nfinal selectedTimeZonesProvider = StateProvider<List<String>>((ref) {\n  return [\n    'Asia/Kolkata',      // IST\n    'America/New_York',  // EST\n    'Europe/London',     // GMT\n    'Asia/Tokyo',        // JST\n  ];\n});\n\nclass DigitalClockScreen extends ConsumerStatefulWidget {\n  const DigitalClockScreen({Key? key}) : super(key: key);\n\n  @override\n  ConsumerState<DigitalClockScreen> createState() => _DigitalClockScreenState();\n}\n\nclass _DigitalClockScreenState extends ConsumerState<DigitalClockScreen> {\n  @override\n  void initState() {\n    super.initState();\n    tzdata.initializeTimeZones();\n  }\n\n  @override\n  Widget build(BuildContext context) {\n    final currentTime = ref.watch(currentTimeProvider);\n    final timeZones = ref.watch(selectedTimeZonesProvider);\n\n    return Scaffold(\n      appBar: AppBar(\n        title: const Text('World Clock'),\n        centerTitle: true,\n        elevation: 0,\n      ),\n      body: currentTime.when(\n        loading: () => const Center(child: CircularProgressIndicator()),\n        error: (error, stack) => Center(child: Text('Error: $error')),\n        data: (time) => SingleChildScrollView(\n          child: Column(\n            children: [\n              // Main Digital Clock (Local Time)\n              _buildMainClock(time),\n              const SizedBox(height: 32),\n              // Time Zone Clocks\n              _buildTimeZoneClocks(time, timeZones),n            ],\n          ),\n        ),\n      ),\n      floatingActionButton: FloatingActionButton(\n        onPressed: () => _showTimeZoneSelector(context, timeZones),\n        tooltip: 'Add Time Zone',\n        child: const Icon(Icons.add),\n      ),\n    );\n  }\n\n  // Main clock displaying current local time\n  Widget _buildMainClock(DateTime time) {\n    return Container(\n      margin: const EdgeInsets.all(24),\n      padding: const EdgeInsets.all(24),\n      decoration: BoxDecoration(\n        gradient: LinearGradient(\n          begin: Alignment.topLeft,\n          end: Alignment.bottomRight,\n          colors: [\n            Theme.of(context).primaryColor,\n            Theme.of(context).primaryColor.withOpacity(0.7),\n          ],\n        ),\n        borderRadius: BorderRadius.circular(20),\n        boxShadow: [\n          BoxShadow(\n            color: Theme.of(context).primaryColor.withOpacity(0.3),\n            blurRadius: 20,\n            offset: const Offset(0, 10),\n          ),\n        ],\n      ),\n      child: Column(\n        mainAxisAlignment: MainAxisAlignment.center,\n        children: [\n          Text(\n            'Local Time',\n            style: Theme.of(context).textTheme.bodySmall?.copyWith(\n              color: Colors.white70,\n              fontSize: 14,\n            ),\n          ),\n          const SizedBox(height: 16),\n          Text(\n            _formatTime(time),\n            style: Theme.of(context).textTheme.displayLarge?.copyWith(\n              color: Colors.white,\n              fontWeight: FontWeight.bold,\n              letterSpacing: 2,\n            ),\n          ),\n          const SizedBox(height: 12),\n          Text(\n            _formatDate(time),\n            style: Theme.of(context).textTheme.bodyMedium?.copyWith(\n              color: Colors.white70,\n            ),\n          ),\n        ],\n      ),\n    );\n  }\n\n  // Build time zone clocks\n  Widget _buildTimeZoneClocks(DateTime time, List<String> timeZones) {\n    return Column(\n      children: [\n        Padding(\n          padding: const EdgeInsets.symmetric(horizontal: 24, vertical: 16),\n          child: Text(\n            'World Time Zones',\n            style: Theme.of(context).textTheme.headlineSmall,\n          ),\n        ),\n        ListView.builder(\n          shrinkWrap: true,\n          physics: const NeverScrollableScrollPhysics(),\n          itemCount: timeZones.length,\n          itemBuilder: (context, index) {\n            final timeZoneName = timeZones[index];\n            return _buildTimeZoneCard(\n              time,\n              timeZoneName,\n              index,\n              timeZones.length,\n              onRemove: () => _removeTimeZone(timeZoneName),\n            );\n          },\n        ),\n      ],\n    );\n  }\n\n  // Individual time zone card\n  Widget _buildTimeZoneCard(\n    DateTime time,\n    String timeZoneName,\n    int index,\n    int total,\n    VoidCallback onRemove,\n  ) {\n    final tzLocation = tz.getLocation(timeZoneName);\n    final tzTime = tz.TZDateTime.from(time, tzLocation);\n    final abbreviation = tzTime.timeZoneName;\n    final offset = _getTimeZoneOffset(tzTime);\n\n    return Container(\n      margin: EdgeInsets.fromLTRB(\n        24,\n        index == 0 ? 0 : 12,\n        24,\n        index == total - 1 ? 24 : 0,\n      ),\n      decoration: BoxDecoration(\n        color: Colors.white,\n        borderRadius: BorderRadius.circular(16),\n        boxShadow: [\n          BoxShadow(\n            color: Colors.grey.withOpacity(0.1),\n            blurRadius: 10,\n            offset: const Offset(0, 4),\n          ),\n        ],\n      ),\n      child: Material(\n        color: Colors.transparent,\n        child: InkWell(\n          onLongPress: onRemove,\n          borderRadius: BorderRadius.circular(16),\n          child: Padding(\n            padding: const EdgeInsets.all(16),\n            child: Row(\n              mainAxisAlignment: MainAxisAlignment.spaceBetween,\n              children: [\n                Expanded(\n                  child: Column(\n                    crossAxisAlignment: CrossAxisAlignment.start,\n                    children: [\n                      Text(\n                        _getTimeZoneDisplayName(timeZoneName),\n                        style: Theme.of(context).textTheme.titleMedium?.copyWith(\n                          fontWeight: FontWeight.bold,\n                        ),\n                      ),\n                      const SizedBox(height: 4),\n                      Text(\n                        '$abbreviation • UTC$offset',\n                        style: Theme.of(context).textTheme.bodySmall?.copyWith(\n                          color: Colors.grey[600],\n                        ),\n                      ),\n                    ],\n                  ),\n                ),\n                Column(\n                  crossAxisAlignment: CrossAxisAlignment.end,\n                  children: [\n                    Text(\n                      _formatTime(tzTime),\n                      style: Theme.of(context).textTheme.headlineSmall?.copyWith(\n                        fontWeight: FontWeight.bold,\n                        color: Theme.of(context).primaryColor,\n                        fontFamily: 'monospace',\n                      ),\n                    ),\n                    const SizedBox(height: 4),\n                    Text(\n                      _formatDate(tzTime),\n                      style: Theme.of(context).textTheme.bodySmall?.copyWith(\n                        color: Colors.grey[600],\n                      ),\n                    ),\n                  ],\n                ),\n              ],\n            ),\n          ),\n        ),\n      ),\n    );\n  }\n\n  // Time zone selector dialog\n  void _showTimeZoneSelector(BuildContext context, List<String> currentZones) {\n    showDialog(\n      context: context,\n      builder: (context) => _TimeZoneSelectorDialog(\n        currentTimeZones: currentZones,\n        onTimeZonesSelected: (newZones) {\n          ref.read(selectedTimeZonesProvider.notifier).state = newZones;\n        },\n      ),\n    );\n  }\n\n  void _removeTimeZone(String timeZone) {\n    ref.read(selectedTimeZonesProvider.notifier).update(\n      (state) => state.where((tz) => tz != timeZone).toList(),\n    );\n  }\n\n  // Format time as HH:MM:SS\n  String _formatTime(DateTime time) {\n    return '${time.hour.toString().padLeft(2, '0')}:${time.minute.toString().padLeft(2, '0')}:${time.second.toString().padLeft(2, '0')}';\n  }\n\n  // Format date\n  String _formatDate(DateTime time) {\n    final days = ['Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat', 'Sun'];\n    final months = ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun', 'Jul', 'Aug', 'Sep', 'Oct', 'Nov', 'Dec'];\n    return '${days[time.weekday - 1]}, ${months[time.month - 1]} ${time.day}, ${time.year}';\n  }\n\n  // Get time zone offset\n  String _getTimeZoneOffset(tz.TZDateTime time) {\n    final offset = time.offset ~/ 3600000;\n    final sign = offset >= 0 ? '+' : '';\n    final hours = (offset.abs() ~/ 60).toString().padLeft(2, '0');\n    final minutes = (offset.abs() % 60).toString().padLeft(2, '0');\n    return '$sign${(offset ~/ 60).toString().padLeft(2, '0')}:$minutes';\n  }\n\n  // Get display name for time zone\n  String _getTimeZoneDisplayName(String timeZone) {\n    final parts = timeZone.split('/');\n    return parts.last.replaceAll('_', ' ');\n  }\n}\n\n// Time Zone Selector Dialog\nclass _TimeZoneSelectorDialog extends ConsumerWidget {\n  final List<String> currentTimeZones;\n  final Function(List<String>) onTimeZonesSelected;\n\n  const _TimeZoneSelectorDialog({\n    required this.currentTimeZones,\n    required this.onTimeZonesSelected,\n  });\n\n  @override\n  Widget build(BuildContext context, WidgetRef ref) {\n    final selectedZones = <String>{...currentTimeZones};\n    final allTimeZones = _getAllTimeZones();\n\n    return StatefulBuilder(\n      builder: (context, setState) => AlertDialog(\n        title: const Text('Select Time Zones'),\n        content: SizedBox(\n          width: double.maxFinite,\n          child: ListView.builder(\n            shrinkWrap: true,\n            itemCount: allTimeZones.length,\n            itemBuilder: (context, index) {\n              final timeZone = allTimeZones[index];\n              final isSelected = selectedZones.contains(timeZone);\n\n              return CheckboxListTile(\n                title: Text(timeZone),\n                value: isSelected,\n                onChanged: (value) {\n                  setState(() {\n                    if (value == true) {\n                      selectedZones.add(timeZone);\n                    } else {\n                      selectedZones.remove(timeZone);\n                    }\n                  });\n                },\n              );\n            },\n          ),\n        ),\n        actions: [\n          TextButton(\n            onPressed: () => Navigator.pop(context),\n            child: const Text('Cancel'),\n          ),\n          ElevatedButton(\n            onPressed: () {\n              onTimeZonesSelected(selectedZones.toList());\n              Navigator.pop(context);\n            },\n            child: const Text('Save'),\n          ),\n        ],\n      ),\n    );\n  }\n\n  List<String> _getAllTimeZones() {\n    return [\n      'Asia/Kolkata',\n      'Asia/Tokyo',\n      'Asia/Shanghai',\n      'Asia/Hong_Kong',\n      'Asia/Singapore',\n      'Asia/Dubai',\n      'Asia/Bangkok',\n      'Australia/Sydney',\n      'Australia/Melbourne',\n      'Pacific/Auckland',\n      'Europe/London',\n      'Europe/Paris',\n      'Europe/Berlin',\n      'Europe/Moscow',\n      'Africa/Cairo',\n      'Africa/Johannesburg',\n      'America/New_York',\n      'America/Chicago',\n      'America/Denver',\n      'America/Los_Angeles',\n      'America/Anchorage',\n      'America/Toronto',\n      'America/Mexico_City',\n      'America/Sao_Paulo',\n      'America/Buenos_Aires',\n      'Pacific/Fiji',\n      'Pacific/Honolulu',\n    ]..sort();\n  }\n}\n